% Vectorized version of analyzeProcessNoiseFOGM.m with fully vectorized plotting
% All nested loops replaced using ndgrid + arrayfun + matrix plotting
% Uses evalMappedProcessNoiseFOGM(dDeltaTstep, dSigma2WN, dTimeConst, dDefaultDeltaTstep, bBetaVariant, dDefaultProcessQcov)
% NOTE: automatically generated by GPT o4-mini-high, reviewed and adapted by Pietro Califano, 04-06-2025

clearvars
close all
clc

%% 1) Define ranges and defaults
ui8NumDt = uint8(50);

dDeltaTstepVec = linspace(0.01, 1.0, ui8NumDt);    % [s] Δt from 0.01 to 1 second

dSigma2WNVec   = [0.1, 1.0, 10.0];                 % [units²/s]
dTimeConstVec  = [0.2, 0.5, 1.0, 2.0];             % [s]

% Default values for evalMappedProcessNoiseFOGM
dDefaultDeltaTstep   = 0.1;    % [s]
dDefaultProcessQcov  = 1.0;    % [units²]
bBetaVariant         = false;  % standard FOGM mapping

%% 2) Generate 3D grid of parameters
% ndgrid order: (dDeltaTstepVec, dTimeConstVec, dSigma2WNVec)
[DtGrid, TauGrid, SigmaGrid] = ndgrid(dDeltaTstepVec, dTimeConstVec, dSigma2WNVec);

%% 3) Compute Q for all combinations using arrayfun
fHandle = @(dDeltaTstep, dTimeConst, dSigma2WN) evalMappedProcessNoiseFOGM( ...
    dDeltaTstep, dSigma2WN, dTimeConst, dDefaultDeltaTstep, bBetaVariant, dDefaultProcessQcov );
dProcessNoiseCovAll = arrayfun(fHandle, DtGrid, TauGrid, SigmaGrid);
% dProcessNoiseCovAll: [numel(dDeltaTstepVec) × numel(dTimeConstVec) × numel(dSigma2WNVec)]

%% 4) Plot: Q vs. Δt for all τ at each σ² (vectorized)
for idxSigma = 1:numel(dSigma2WNVec)
    dSigma2WN = dSigma2WNVec(idxSigma);
    % Extract matrix [Dt x Tau] for this σ²
    Qmat = squeeze(dProcessNoiseCovAll(:, :, idxSigma));  % size [length(dDeltaTstepVec) × length(dTimeConstVec)]

    figure('Name', sprintf('Q vs Δt (σ²=%.1f)', dSigma2WN), 'NumberTitle','off');
    plot(dDeltaTstepVec, Qmat, 'LineWidth', 1.5);
    grid on;
    xlabel('\Delta t [s]');
    ylabel('Q_{FOGM} [units^2]');
    title(sprintf('FOGM process-noise covariance vs Δt (\sigma^2 = %.1f)', dSigma2WN));
    % Build legend entries for each τ
    legend(arrayfun(@(tau) sprintf('\\tau = %.2f s', tau), dTimeConstVec, 'UniformOutput', false), ...
        'Location','northwest');
end

%% 5) Plot: Q vs. τ for all Δt at each σ² (vectorized)
for idxSigma = 1:numel(dSigma2WNVec)
    dSigma2WN = dSigma2WNVec(idxSigma);
    % Extract matrix [Dt x Tau] then transpose to [Tau x Dt]
    Qmat = squeeze(dProcessNoiseCovAll(:, :, idxSigma)).';  % size [length(dTimeConstVec) × length(dDeltaTstepVec)]

    figure('Name', sprintf('Q vs τ (σ²=%.1f)', dSigma2WN), 'NumberTitle','off');
    semilogx(dTimeConstVec, Qmat, 'LineWidth', 1.2);
    grid on;
    xlabel('\tau [s] (log scale)');
    ylabel('Q_{FOGM} [units^2]');
    title(sprintf('FOGM process-noise covariance vs \tau (\sigma^2 = %.1f)', dSigma2WN));
    % Legend for each Δt
    legend(arrayfun(@(dt) sprintf('\\Delta t = %.2f s', dt), dDeltaTstepVec, 'UniformOutput', false), ...
        'Location','northeastoutside');
end

%% 6) Surface plot: Q vs. Δt and τ at σ² = 1.0
idxSigmaMid = find(dSigma2WNVec == 1.0, 1);
if isempty(idxSigmaMid)
    idxSigmaMid = 2;
end
Qslice = squeeze(dProcessNoiseCovAll(:, :, idxSigmaMid));  % [Dt × Tau]
QmatSurface = Qslice.';  % [Tau × Dt]
[DtPlotGrid, TauPlotGrid] = meshgrid(dDeltaTstepVec, dTimeConstVec);
figure('Name', sprintf('Surface: Q vs Δt and τ (σ²=%.1f)', dSigma2WNVec(idxSigmaMid)), 'NumberTitle','off');
surf(DtPlotGrid, TauPlotGrid, QmatSurface);
xlabel('\Delta t [s]');
ylabel('\tau [s]');
zlabel('Q_{FOGM} [units^2]');
title(sprintf('Surface of FOGM Q vs \Delta t & \tau (\sigma^2 = %.1f)', dSigma2WNVec(idxSigmaMid)));
colorbar;

%% 7) Numeric analysis: Q at Δt = 0.1 s (vectorized extraction)
dTargetDeltaT = 0.1;
[~, idxTargetDt] = min(abs(dDeltaTstepVec - dTargetDeltaT));
% Extract matrix [Tau x Sigma] for Δt ≈ 0.1
QatTarget = squeeze(dProcessNoiseCovAll(idxTargetDt, :, :));  % size [length(dTimeConstVec) × length(dSigma2WNVec)]

fprintf('\n--- Q @ Δt = %.2f s for various σ² and τ: ---\n', dDeltaTstepVec(idxTargetDt));
for idxSigma = 1:numel(dSigma2WNVec)
    dSigma2WN = dSigma2WNVec(idxSigma);
    fprintf('σ² = %.2f:\n', dSigma2WN);
    Qcol = QatTarget(:, idxSigma);  % column of size [length(dTimeConstVec) × 1]
    % Print τ vs Q without inner loop
    cellfun(@(tau, Qval) fprintf('  τ = %.2f s → Q = %.4e\n', tau, Qval), ...
        num2cell(dTimeConstVec), num2cell(Qcol));
end
